import Phaser from "phaser";
import { io } from "socket.io-client";

const env = import.meta.env as ImportMeta["env"] & { VITE_SERVER_URL?: string; VITE_AUTH_BYPASS?: string };
const SERVER_URL = env.VITE_SERVER_URL ?? "http://localhost:4000";
const AUTH_BYPASS = env.VITE_AUTH_BYPASS === "true";

class LobbyScene extends Phaser.Scene {
  private socket = io(SERVER_URL, {
    autoConnect: AUTH_BYPASS
  });

  constructor() {
    super("lobby");
  }

  create(): void {
    const text = this.add.text(20, 20, "Agantu 4P Lobby\nConnect auth token then join room", {
      color: "#ffffff"
    });
    text.setDepth(1);
  }
}

const game = new Phaser.Game({
  type: Phaser.AUTO,
  width: 1280,
  height: 720,
  parent: "app",
  backgroundColor: "#1c2230",
  scene: [LobbyScene]
});

window.addEventListener("beforeunload", () => game.destroy(true));
